const config = $('Set Config').first().json;
const stocks = $('HTTP Acoes BR').first().json.results || [];
const btc = $('HTTP Bitcoin').first().json.bitcoin || {};
const newsBr = $('HTTP Noticias BR').first().json.articles || [];
const newsBtc = $('HTTP Noticias BTC').first().json.articles || [];

const stockText = stocks.map((s) => {
  const price = s.regularMarketPrice ?? 'n/d';
  const changePct = s.regularMarketChangePercent ?? 'n/d';
  const high = s.regularMarketDayHigh ?? 'n/d';
  const low = s.regularMarketDayLow ?? 'n/d';
  const volume = s.regularMarketVolume ?? 'n/d';
  const marketCap = s.marketCap ?? 'n/d';

  return [
    `Ativo: ${s.symbol}`,
    `Nome: ${s.shortName || s.longName || 'n/d'}`,
    `Preco atual: ${price}`,
    `Variacao no dia: ${changePct}%`,
    `Maxima do dia: ${high}`,
    `Minima do dia: ${low}`,
    `Volume: ${volume}`,
    `Valor de mercado: ${marketCap}`,
  ].join('\n');
}).join('\n\n');

const btcText = [
  'Ativo: BITCOIN',
  `Preco BRL: ${btc.brl ?? 'n/d'}`,
  `Preco USD: ${btc.usd ?? 'n/d'}`,
  `Variacao em 24h: ${btc.brl_24h_change ?? btc.usd_24h_change ?? 'n/d'}%`,
  `Ultima atualizacao: ${btc.last_updated_at ?? 'n/d'}`,
].join('\n');

const newsText = [...newsBr, ...newsBtc]
  .slice(0, 14)
  .map((n, index) => [
    `${index + 1}. ${n.title || 'Sem titulo'}`,
    `Fonte: ${n.source?.name || 'n/d'}`,
    `Publicado em: ${n.publishedAt || 'n/d'}`,
    `Resumo: ${n.description || 'Sem resumo'}`,
    `Link: ${n.url || 'n/d'}`,
  ].join('\n'))
  .join('\n\n');

const prompt = `Voce e um analista financeiro objetivo, prudente e claro. Analise os ativos PETR4, TAEE11, VALE3, ITSA4, BBAS3, BBSE3, MXRF11, XPML11, GARE11, VGHF11, VISC11 e BITCOIN usando somente os dados e noticias abaixo.\n\nPara cada ativo, entregue:\n- leitura rapida do movimento atual\n- noticias ou fatos relevantes\n- riscos e pontos de atencao\n- conclusao em uma destas categorias: comprar aos poucos, segurar, evitar aumentar posicao\n\nRegras:\n- nao invente dados\n- nao faca promessa de rentabilidade\n- seja util para investidor pessoa fisica de medio e longo prazo\n- escreva em portugues do Brasil\n- se faltarem dados, deixe isso explicito\n- para FIIs, considere vacancia, qualidade dos ativos, diversificacao e sensibilidade a juros quando houver dados suficientes\n\nNo final, gere:\n- um resumo executivo de 5 a 8 linhas\n- os 3 ativos mais interessantes no momento\n- os 2 ativos que exigem mais cautela\n\nDados de mercado:\n${stockText}\n\n${btcText}\n\nNoticias recentes:\n${newsText}`;

return [{
  json: {
    email: config.email,
    prompt,
    contexto: {
      stocks,
      bitcoin: btc,
      newsBr,
      newsBtc,
    },
  },
}];

const email = $('Preparar Prompt').first().json.email;
const response = $json;

let analysis = '';

if (typeof response.output_text === 'string' && response.output_text.trim()) {
  analysis = response.output_text.trim();
} else if (Array.isArray(response.output)) {
  const texts = [];
  for (const item of response.output) {
    if (Array.isArray(item.content)) {
      for (const content of item.content) {
        if (content.type === 'output_text' && content.text) {
          texts.push(content.text);
        }
      }
    }
  }
  analysis = texts.join('\n\n').trim();
}

if (!analysis) {
  analysis = 'Nao foi possivel extrair a analise automaticamente da resposta da OpenAI. Revise o no OpenAI Analise.';
}

const html = `
<h2>Analise diaria de ativos</h2>
<p>Data: ${$now.setZone('America/Sao_Paulo').toFormat('dd/MM/yyyy HH:mm')}</p>
<pre style="white-space: pre-wrap; font-family: Arial, sans-serif; font-size: 14px; line-height: 1.5;">${analysis.replace(/</g, '&lt;').replace(/>/g, '&gt;')}</pre>
<p>Mensagem automatica enviada pelo n8n.</p>
`.trim();

return [{ json: { email, analysis, html } }];
